from flask import Flask, send_file, abort, make_response
from io import BytesIO

app = Flask(__name__)

INVOICES = {
    1: b"%PDF-1.4\n%Fake invoice PDF content for invoice 1\n",
    2: b"%PDF-1.4\n%Fake invoice PDF content for invoice 2\n",
    3: b"%PDF-1.4\n%Fake invoice PDF content for invoice 3\n",
}

@app.route("/api/invoices/<int:invoice_id>/download", methods=["GET"])
def download_invoice(invoice_id):
    pdf_bytes = INVOICES.get(invoice_id)
    if pdf_bytes is None:
        abort(404)

    file_obj = BytesIO(pdf_bytes)
    response = make_response(send_file(
        file_obj,
        mimetype="application/pdf",
        as_attachment=True,
        download_name=f"invoice_{invoice_id}.pdf",
        max_age=0,
    ))
    response.headers["Cache-Control"] = "no-store"
    return response

if __name__ == "__main__":
    app.run()